// import { createRouter, createWebHistory } from 'vue-router'
import { createRouter, createWebHashHistory } from 'vue-router'

const routes = [
  {
    path: '/',
    component: () => import('@/views/website'),
    children: [
      {
          path: '/',
          name: 'home',
          component: () => import('@/views/website/pages/home')
      },
      // {
      //     path: '/about',
      //     name: 'about',
      //     component: () => import('@/views/About.vue')
      // }
    ]
  },
  {
    path: '/test',
    name: 'test',
    props: true,
    component: () => import('@/views/test'),
  },
  {
    path: '/note',
    name: 'Note',
    props: true,
    component: () => import('@/views/note'),
  },
  {
    path: '/handbook',
    name: 'Handbook',
    props: true,
    component: () => import('@/views/handbook'),
  },
  {
    path: '/WhatIsMyViewport',
    name: 'WhatIsMyViewport',
    props: true,
    component: () => import('@/views/what-is-my-viewport'),
  },
  {
    path: '/cocktails',
    name: 'Cocktails',
    props: true,
    component: () => import('@/views/cocktails'),
  },
  {
    path: '/:pathMatch(.*)',
    component: () => import('@/views/not-found'),
  }
];

const router = createRouter({
  history: createWebHashHistory(),
  routes
});

export default router;
